namespace sv_09dbeb491c024c84a4c8fcc5a8a7cf18.Services;

public class WarehouseStateService
{
    private string _currentWarehouseId = "WH-001";

    public event Action? OnChange;

    public string CurrentWarehouseId
    {
        get => _currentWarehouseId;
        set
        {
            if (_currentWarehouseId == value)
                return;
            _currentWarehouseId = value;
            OnChange?.Invoke();
        }
    }

    public static IReadOnlyList<(string Id, string Name)> AvailableWarehouses { get; } =
    [
        ("WH-001", "Warehouse A — East"),
        ("WH-002", "Warehouse B — West"),
        ("WH-003", "Warehouse C — Central"),
    ];
}

namespace sv_09dbeb491c024c84a4c8fcc5a8a7cf18.Services;

public class InventoryAlertService
{
    private static readonly Random _random = new();

    private int _lastCount;

    /// <summary>
    /// Fired whenever a new alert count is available so every subscriber can re-render.
    /// </summary>
    public event Action? OnAlertCountChanged;

    /// <summary>
    /// Most recently fetched alert count. Subscribers can read this without an async call.
    /// </summary>
    public int CurrentAlertCount => _lastCount;

    /// <summary>
    /// Simulates a database query that returns the number of items below minimum stock levels.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate I/O latency + random result
        var count = _random.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Fetches a new count and broadcasts the result to all subscribers.
    /// </summary>
    public async Task RefreshAlertCountAsync(string warehouseId)
    {
        _lastCount = await GetLowStockCountAsync(warehouseId);
        OnAlertCountChanged?.Invoke();
    }
}

