@rendermode InteractiveServer
@inject sv_09dbeb491c024c84a4c8fcc5a8a7cf18.Services.WarehouseStateService WarehouseState
@implements IDisposable

<div class="warehouse-selector d-flex align-items-center gap-2 px-3 py-2">
    <label class="form-label mb-0 text-white small fw-semibold" for="warehouseSelect">Site:</label>
    <select id="warehouseSelect"
            class="form-select form-select-sm"
            style="max-width: 220px;"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var (id, name) in sv_09dbeb491c024c84a4c8fcc5a8a7cf18.Services.WarehouseStateService.AvailableWarehouses)
        {
            <option value="@id">@name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        WarehouseState.CurrentWarehouseId = e.Value?.ToString() ?? "WH-001";
    }

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@rendermode InteractiveServer
@inject sv_09dbeb491c024c84a4c8fcc5a8a7cf18.Services.InventoryAlertService AlertService
@inject sv_09dbeb491c024c84a4c8fcc5a8a7cf18.Services.WarehouseStateService WarehouseState
@implements IDisposable

<span class="badge rounded-pill @BadgeClass">@AlertService.CurrentAlertCount</span>

@code {
    private string BadgeClass =>
        AlertService.CurrentAlertCount switch
        {
            0 => "bg-success",
            <= 5 => "bg-warning text-dark",
            _ => "bg-danger"
        };

    protected override void OnInitialized()
    {
        AlertService.OnAlertCountChanged += OnAlertCountChanged;
        WarehouseState.OnChange += OnWarehouseChanged;
    }

    private void OnAlertCountChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private async void OnWarehouseChanged()
    {
        await AlertService.RefreshAlertCountAsync(WarehouseState.CurrentWarehouseId);
        // OnAlertCountChanged will trigger StateHasChanged for this and all other subscribers
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= OnAlertCountChanged;
        WarehouseState.OnChange -= OnWarehouseChanged;
    }
}

