arguments.file_text:
@page "/dashboard"
@rendermode InteractiveServer
@inject sv_09dbeb491c024c84a4c8fcc5a8a7cf18.Services.WarehouseStateService WarehouseState
@inject sv_09dbeb491c024c84a4c8fcc5a8a7cf18.Services.InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Current Site</h5>
                <p class="card-text fs-5">
                    @(sv_09dbeb491c024c84a4c8fcc5a8a7cf18.Services.WarehouseStateService.AvailableWarehouses
                        .FirstOrDefault(w => w.Id == WarehouseState.CurrentWarehouseId).Name
                        ?? WarehouseState.CurrentWarehouseId)
                </p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="card-text">
                    <span class="fs-1 fw-bold @AlertTextClass">@AlertService.CurrentAlertCount</span>
                </p>
                <p class="text-muted small mb-0">
                    items below minimum &bull; refreshes every 10 s
                </p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="card-text">
                    @if (_isPolling)
                    {
                        <span class="text-success">● Active</span>
                    }
                    else
                    {
                        <span class="text-secondary">○ Stopped</span>
                    }
                </p>
                <p class="text-muted small mb-0">Last check: @_lastPollTime?.ToString("HH:mm:ss")</p>
            </div>
        </div>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;
    private bool _isPolling;
    private DateTime? _lastPollTime;

    private string AlertTextClass =>
        AlertService.CurrentAlertCount switch
        {
            0 => "text-success",
            <= 5 => "text-warning",
            _ => "text-danger"
        };

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        AlertService.OnAlertCountChanged += OnAlertCountChanged;

        // Initial fetch, then start polling
        await AlertService.RefreshAlertCountAsync(WarehouseState.CurrentWarehouseId);
        _lastPollTime = DateTime.Now;
        StartPolling();
    }

    private void StartPolling()
    {
        _cts?.Cancel();
        _cts = new CancellationTokenSource();
        _isPolling = true;
        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await AlertService.RefreshAlertCountAsync(WarehouseState.CurrentWarehouseId);
                _lastPollTime = DateTime.Now;
                // OnAlertCountChanged will cause re-render for this AND the sidebar badge
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose / warehouse change
        }
    }

    private async void OnWarehouseChanged()
    {
        // Restart polling for the new warehouse and do an immediate refresh
        StartPolling();
        await AlertService.RefreshAlertCountAsync(WarehouseState.CurrentWarehouseId);
        _lastPollTime = DateTime.Now;
    }

    private void OnAlertCountChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        _isPolling = false;
        _cts?.Cancel();
        _cts?.Dispose();
        WarehouseState.OnChange -= OnWarehouseChanged;
        AlertService.OnAlertCountChanged -= OnAlertCountChanged;
    }
}

